export type ParsedFinalizeSessionInstruction<
  TProgram extends string = typeof PHALNX_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    payer: TAccountMetas[0];
    vault: TAccountMetas[1];
    /**
     * Session rent is returned to the session's agent (who paid for it).
     * Seeds include token_mint for per-token concurrent sessions.
     */
    session: TAccountMetas[2];
    sessionRentRecipient: TAccountMetas[3];
    /** Policy config for cap checking during non-stablecoin swap finalization */
    policy: TAccountMetas[4];
    /** Zero-copy SpendTracker for recording non-stablecoin swap value */
    tracker: TAccountMetas[5];
    /** Zero-copy AgentSpendOverlay — per-agent rolling spend */
    agentSpendOverlay: TAccountMetas[6];
    /** Vault's PDA token account for the session's token */
    vaultTokenAccount?: TAccountMetas[7] | undefined;
    /**
     * Vault's stablecoin ATA for non-stablecoin→stablecoin swap verification.
     * Required when session.output_mint != Pubkey::default().
     */
    outputStablecoinAccount?: TAccountMetas[8] | undefined;
    tokenProgram: TAccountMetas[9];
    systemProgram: TAccountMetas[10];
    /** Instructions sysvar for post-finalize instruction verification. */
    instructionsSysvar: TAccountMetas[11];
  };
  data: FinalizeSessionInstructionData;
};

export function parseFinalizeSessionInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedFinalizeSessionInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 12) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 12,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === PHALNX_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      payer: getNextAccount(),
      vault: getNextAccount(),
      session: getNextAccount(),
      sessionRentRecipient: getNextAccount(),
      policy: getNextAccount(),
      tracker: getNextAccount(),
      agentSpendOverlay: getNextAccount(),
      vaultTokenAccount: getNextOptionalAccount(),
      outputStablecoinAccount: getNextOptionalAccount(),
      tokenProgram: getNextAccount(),
      systemProgram: getNextAccount(),
      instructionsSysvar: getNextAccount(),
    },
    data: getFinalizeSessionInstructionDataDecoder().decode(instruction.data),
  };
}
